begin;
create table if not exists public.lead_prediction_explanations(
 id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,lead_id uuid not null references public.leads(id) on delete cascade,
 feature_cutoff_at timestamptz not null,raw_probability numeric(5,2) not null check(raw_probability between 0 and 100),calibrated_probability numeric(5,2) not null check(calibrated_probability between 0 and 100),confidence integer not null check(confidence between 0 and 100),band text not null check(band in('very_low','low','medium','high','very_high')),
 positive_factor_keys text[] not null default '{}',risk_factor_keys text[] not null default '{}',missing_signal_keys text[] not null default '{}',recommended_action_key text not null,
 source_model_version text not null,calibration_model_id uuid references public.conversion_calibration_models(id) on delete set null,calibration_version integer,expires_at timestamptz not null,created_by uuid not null references public.profiles(id),created_at timestamptz not null default now()
);
create index if not exists lead_prediction_explanations_latest_idx on public.lead_prediction_explanations(organization_id,lead_id,created_at desc);
alter table public.lead_prediction_explanations enable row level security;drop policy if exists lead_prediction_explanations_scope on public.lead_prediction_explanations;create policy lead_prediction_explanations_scope on public.lead_prediction_explanations for select to authenticated using(organization_id=(select public.current_organization_id())and(select private.can_view_lead(lead_id)));revoke all on public.lead_prediction_explanations from anon;revoke insert,update,delete on public.lead_prediction_explanations from authenticated;grant select on public.lead_prediction_explanations to authenticated;grant all on public.lead_prediction_explanations to service_role;

create or replace function public.build_lead_prediction_explanation(p_actor_id uuid,p_organization_id uuid,p_lead_id uuid)
returns jsonb language plpgsql security definer set search_path='' as $$declare actor_role text;lead_row public.leads%rowtype;events integer:=0;positive_events integer:=0;negative_events integer:=0;visits integer:=0;proposals integer:=0;last_event timestamptz;raw numeric;calibrated numeric;confidence_value integer;band_value text;positive_keys text[]:='{}';risk_keys text[]:='{}';missing_keys text[]:='{}';action_key text;calibration public.conversion_calibration_models%rowtype;explanation_id uuid;
begin select coalesce(commercial_role,case role when'admin'then'director'else role end)into actor_role from public.profiles where id=p_actor_id and organization_id=p_organization_id and active=true;select*into lead_row from public.leads where id=p_lead_id and organization_id=p_organization_id;if not found or actor_role is null then raise exception 'prediction_explanation_forbidden';end if;if actor_role='broker'and lead_row.assigned_to is distinct from p_actor_id then raise exception 'prediction_explanation_forbidden';end if;if actor_role in('manager','superintendent')and not exists(with recursive descendants as(select id from public.profiles where id=p_actor_id and organization_id=p_organization_id union all select p.id from public.profiles p join descendants d on p.reports_to=d.id where p.organization_id=p_organization_id and p.active=true)select 1 from descendants where id=lead_row.assigned_to)then raise exception 'prediction_explanation_forbidden';end if;if actor_role not in('director','superintendent','manager','broker')then raise exception 'prediction_explanation_forbidden';end if;
 select count(*),count(*)filter(where direction='positive'),count(*)filter(where direction='negative'),count(*)filter(where event_category='visit'),count(*)filter(where event_category='proposal'),max(occurred_at)into events,positive_events,negative_events,visits,proposals,last_event from public.lead_behavior_events where organization_id=p_organization_id and lead_id=p_lead_id;
 raw:=greatest(1,least(95,10+coalesce(lead_row.score,0)*.55+case lower(coalesce(lead_row.status,'novo'))when'contato'then 4 when'qualificacao'then 12 when'visita'then 20 when'proposta'then 30 when'contrato'then 42 else 0 end));select*into calibration from public.conversion_calibration_models where organization_id=p_organization_id and status='active'limit 1;calibrated:=public.apply_active_conversion_calibration(p_organization_id,raw);
 if coalesce(lead_row.score,0)>=70 then positive_keys:=array_append(positive_keys,'score_high');elsif coalesce(lead_row.score,0)<35 then risk_keys:=array_append(risk_keys,'score_low');end if;if lower(coalesce(lead_row.status,'novo'))in('visita','proposta','contrato')then positive_keys:=array_append(positive_keys,'stage_advanced');end if;if events>=3 then positive_keys:=array_append(positive_keys,'engagement_observed');elsif events=0 then risk_keys:=array_append(risk_keys,'no_engagement');end if;if visits>0 then positive_keys:=array_append(positive_keys,'visit_signal');end if;if proposals>0 then positive_keys:=array_append(positive_keys,'proposal_signal');end if;if negative_events>=2 then risk_keys:=array_append(risk_keys,'repeated_negative_signals');end if;if last_event is not null and last_event>=now()-interval'7 days'then positive_keys:=array_append(positive_keys,'recent_interaction');elsif last_event is null or last_event<now()-interval'14 days'then risk_keys:=array_append(risk_keys,'stale_interaction');end if;if lead_row.next_action_at is null then missing_keys:=array_append(missing_keys,'next_action');elsif lead_row.next_action_at<now()then risk_keys:=array_append(risk_keys,'next_action_overdue');end if;if coalesce(lead_row.data_quality_percent,0)>=80 then positive_keys:=array_append(positive_keys,'data_quality_high');elsif coalesce(lead_row.data_quality_percent,0)<50 then risk_keys:=array_append(risk_keys,'data_quality_low');end if;if coalesce(lead_row.data_quality_issues,'{}')@>array['contact']then missing_keys:=array_append(missing_keys,'valid_contact');end if;
 confidence_value:=greatest(30,least(95,35+round(coalesce(lead_row.data_quality_percent,0)*.35)::integer+least(20,events*2)+case when calibration.id is not null then 10 else 0 end));band_value:=case when calibrated>=75 then'very_high'when calibrated>=58 then'high'when calibrated>=38 then'medium'when calibrated>=20 then'low'else'very_low'end;
 action_key:=case when'valid_contact'=any(missing_keys)then'restore_valid_contact'when'next_action_overdue'=any(risk_keys)or'next_action'=any(missing_keys)then'schedule_next_action'when cardinality(missing_keys)>0 then'qualify_missing_data'when lower(coalesce(lead_row.status,'novo'))in('proposta','contrato')then'follow_proposal'when lower(coalesce(lead_row.status,'novo'))='visita'then'confirm_visit_outcome'when lower(coalesce(lead_row.status,'novo'))in('novo','contato')then'complete_qualification'else'maintain_cadence'end;
 insert into public.lead_prediction_explanations(organization_id,lead_id,feature_cutoff_at,raw_probability,calibrated_probability,confidence,band,positive_factor_keys,risk_factor_keys,missing_signal_keys,recommended_action_key,source_model_version,calibration_model_id,calibration_version,expires_at,created_by)values(p_organization_id,p_lead_id,now(),round(raw,2),round(calibrated,2),confidence_value,band_value,positive_keys,risk_keys,missing_keys,action_key,'atlas-baseline-v1',calibration.id,calibration.version,now()+interval'24 hours',p_actor_id)returning id into explanation_id;
 return jsonb_build_object('explanationId',explanation_id,'rawProbability',round(raw,2),'calibratedProbability',round(calibrated,2),'confidence',confidence_value,'band',band_value,'positiveFactors',positive_keys,'riskFactors',risk_keys,'missingSignals',missing_keys,'recommendedAction',action_key,'calibrationApplied',calibration.id is not null,'humanReviewRequired',true,'automaticDecision',false,'llmCost',0);
end $$;
revoke all on function public.build_lead_prediction_explanation(uuid,uuid,uuid)from public,anon,authenticated;grant execute on function public.build_lead_prediction_explanation(uuid,uuid,uuid)to service_role;
commit;
